import heapq

def prims_mst(graph, start=0):
    n = len(graph)
    visited = set()
    mst_edges = []
    total_weight = 0
    # Min-heap: (weight, from_node, to_node)
    heap = [(0, -1, start)]

    while heap and len(visited) < n:
        weight, frm, to = heapq.heappop(heap)
        if to in visited:
            continue
        visited.add(to)
        total_weight += weight
        if frm != -1:
            mst_edges.append((frm, to, weight))
        for neighbor, w in graph[to]:
            if neighbor not in visited:
                heapq.heappush(heap, (w, to, neighbor))

    return total_weight, mst_edges

from collections import defaultdict, OrderedDict

class LFUCache:
    def __init__(self, capacity):
        self.capacity = capacity
        self.key_val = {}
        self.key_freq = {}
        self.freq_keys = defaultdict(OrderedDict)
        self.min_freq = 0

    def get(self, key):
        if key not in self.key_val:
            return -1
        self._update_freq(key)
        return self.key_val[key]

    def put(self, key, value):
        if self.capacity <= 0: return
        if key in self.key_val:
            self.key_val[key] = value
            self._update_freq(key)
            return
        if len(self.key_val) >= self.capacity:
            evict_key, _ = self.freq_keys[self.min_freq].popitem(last=False)
            del self.key_val[evict_key]
            del self.key_freq[evict_key]
        self.key_val[key] = value
        self.key_freq[key] = 1
        self.freq_keys[1][key] = None
        self.min_freq = 1

    def _update_freq(self, key):
        freq = self.key_freq[key]
        del self.freq_keys[freq][key]
        if not self.freq_keys[freq] and freq == self.min_freq:
            self.min_freq += 1
        self.key_freq[key] = freq + 1
        self.freq_keys[freq + 1][key] = None

import random

class SkipNode:
    def __init__(self, val, level):
        self.val = val
        self.forward = [None] * (level + 1)

class SkipList:
    def __init__(self, max_level=16, p=0.5):
        self.max_level = max_level
        self.p = p
        self.level = 0
        self.header = SkipNode(-1, max_level)

    def _random_level(self):
        lvl = 0
        while random.random() < self.p and lvl < self.max_level:
            lvl += 1
        return lvl

    def insert(self, val):
        update = [None] * (self.max_level + 1)
        current = self.header
        for i in range(self.level, -1, -1):
            while current.forward[i] and current.forward[i].val < val:
                current = current.forward[i]
            update[i] = current
        lvl = self._random_level()
        if lvl > self.level:
            for i in range(self.level + 1, lvl + 1):
                update[i] = self.header
            self.level = lvl
        node = SkipNode(val, lvl)
        for i in range(lvl + 1):
            node.forward[i] = update[i].forward[i]
            update[i].forward[i] = node

    def search(self, val):
        current = self.header
        for i in range(self.level, -1, -1):
            while current.forward[i] and current.forward[i].val < val:
                current = current.forward[i]
        current = current.forward[0]
        return current and current.val == val

class CircularBuffer:
    def __init__(self, capacity):
        self.buffer = [None] * capacity
        self.capacity = capacity
        self.head = 0  # read pointer
        self.tail = 0  # write pointer
        self.size = 0

    def write(self, item):
        if self.size == self.capacity:
            raise BufferError('Buffer full')
        self.buffer[self.tail] = item
        self.tail = (self.tail + 1) % self.capacity
        self.size += 1

    def read(self):
        if self.size == 0:
            raise BufferError('Buffer empty')
        item = self.buffer[self.head]
        self.head = (self.head + 1) % self.capacity
        self.size -= 1
        return item

    def __len__(self):
        return self.size

class IntervalNode:
    def __init__(self, low, high):
        self.low = low
        self.high = high
        self.max_high = high
        self.left = self.right = None

class IntervalTree:
    def __init__(self):
        self.root = None

    def insert(self, low, high):
        self.root = self._insert(self.root, low, high)

    def _insert(self, node, low, high):
        if not node:
            return IntervalNode(low, high)
        if low < node.low:
            node.left = self._insert(node.left, low, high)
        else:
            node.right = self._insert(node.right, low, high)
        node.max_high = max(node.max_high, high)
        return node

    def query_overlap(self, low, high):
        results = []
        self._query(self.root, low, high, results)
        return results

    def _query(self, node, low, high, results):
        if not node: return
        if node.low <= high and low <= node.high:
            results.append((node.low, node.high))
        if node.left and node.left.max_high >= low:
            self._query(node.left, low, high, results)
        self._query(node.right, low, high, results)
